                {/* Bottom Label */}
                <div className="absolute bottom-0 left-0 right-0 p-1 bg-black/50 backdrop-blur-sm z-0 pointer-events-none">
                    <h3 className="font-semibold text-white text-xs text-center truncate">
                        {item.name}
                    </h3>
                </div>
